package com.DecisionMakingStatements;

public class If_Else {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int age = 20;

		if (age >= 18) {
		System.out.println("Eligible to vote");
		} 
		
		else{
		System.out.println("Not eligible to vote");
		}

	}

}
